package repeticao.estruturas;import java.util.Scanner;public class EstruturasDeRepeticao {    public static void main(String[] args) {        Scanner inputContador = new Scanner(System.in);        System.out.println("Um número: ");        int contador = inputContador.nextInt();        if (contador < 10 && contador >= 0) {            while (contador <= 10) {                System.out.println("Seu contador agora é: " + contador);                contador++;            }        } else {            while (contador >= 0) {                System.out.println("Seu contador agora é: " + contador);                contador--;            }        }    }}